import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface DailyStats {
  steps: number;
  caloriesBurned: number;
}

interface WeeklyActivity {
  day: string;
  steps: number;
}

interface FitnessData {
  dailyStats: DailyStats;
  weeklyActivity: WeeklyActivity[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const fitnessData = response.data as FitnessData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: metaData.primaryColor }}>
              Daily Fitness Stats
            </Typography>
            <Typography variant="body1" sx={{ color: '#1F2937' }}>
              Steps: {fitnessData.dailyStats.steps.toLocaleString()}
            </Typography>
            <Typography variant="body1" sx={{ color: '#1F2937', mt: 0.5 }}>
              Calories Burned: {fitnessData.dailyStats.caloriesBurned}
            </Typography>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: metaData.primaryColor }}>
              Weekly Activity
            </Typography>
            <BarChart
              height={140}
              series={[
                {
                  data: fitnessData.weeklyActivity.map(d => d.steps),
                  color: metaData.accentColor,
                },
              ]}
              xAxis={[
                {
                  data: fitnessData.weeklyActivity.map(d => d.day),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
